/* ── Vector Search – widgets interactifs ─────────────────────────────────── */

const SCALE  = 33;   // pixels par unité
const COLORS = {
    a:    '#e74c3c',
    b:    '#3498db',
    green:'#27ae60',
    arc:  '#f39c12',
    proj: '#9b59b6',
    grid: '#e8e8e8',
    axis: '#aaa',
};

/* ── Classe widget ─────────────────────────────────────────────────────────── */
class VecWidget {
    constructor(canvasId, mode, initA, initB, ids) {
        this.cv   = document.getElementById(canvasId);
        if (!this.cv) return;
        this.ctx  = this.cv.getContext('2d');
        this.W    = this.cv.width;
        this.H    = this.cv.height;
        this.ox   = this.W / 2;
        this.oy   = this.H / 2;
        this.mode = mode;
        this.vA   = { ...initA };
        this.vB   = { ...initB };
        this.ids  = ids;
        this.drag = null;

        this.cv.addEventListener('mousedown',  e => this._down(e));
        this.cv.addEventListener('mousemove',  e => this._move(e));
        this.cv.addEventListener('mouseup',    () => { this.drag = null; });
        this.cv.addEventListener('mouseleave', () => { this.drag = null; });
        this.cv.addEventListener('touchstart', e => { e.preventDefault(); this._down(e.touches[0]); }, { passive: false });
        this.cv.addEventListener('touchmove',  e => { e.preventDefault(); this._move(e.touches[0]); }, { passive: false });
        this.cv.addEventListener('touchend',   () => { this.drag = null; }, { passive: false });

        this._refresh();
    }

    /* ── Conversions de coordonnées ──────────────────── */
    _w2c(x, y) {
        return [this.ox + x * SCALE, this.oy - y * SCALE];
    }

    _c2w(cx, cy) {
        return { x: (cx - this.ox) / SCALE, y: (this.oy - cy) / SCALE };
    }

    _evPos(e) {
        const r  = this.cv.getBoundingClientRect();
        const sx = this.W / r.width;
        const sy = this.H / r.height;
        return [(e.clientX - r.left) * sx, (e.clientY - r.top) * sy];
    }

    _dist(p, q) {
        return Math.hypot(p[0] - q[0], p[1] - q[1]);
    }

    /* ── Événements souris / tactile ─────────────────── */
    _down(e) {
        const p  = this._evPos(e);
        const pa = this._w2c(this.vA.x, this.vA.y);
        const pb = this._w2c(this.vB.x, this.vB.y);
        if (this._dist(p, pa) < 16)      this.drag = 'a';
        else if (this._dist(p, pb) < 16) this.drag = 'b';
    }

    _move(e) {
        if (!this.drag) return;
        const pos = this._evPos(e);
        const w   = this._c2w(pos[0], pos[1]);
        const clamp = v => Math.max(-4.5, Math.min(4.5, Math.round(v * 2) / 2));
        w.x = clamp(w.x);
        w.y = clamp(w.y);
        if (this.drag === 'a') this.vA = w; else this.vB = w;
        this._refresh();
    }

    /* ── Primitives de dessin ─────────────────────────── */
    _drawGrid() {
        const { ctx, ox, oy, W, H } = this;
        ctx.strokeStyle = COLORS.grid;
        ctx.lineWidth   = 0.5;
        for (let i = -5; i <= 5; i++) {
            const vx  = this._w2c(i, 0)[0];
            const top = this._w2c(0,  5)[1];
            const bot = this._w2c(0, -5)[1];
            ctx.beginPath(); ctx.moveTo(vx, top); ctx.lineTo(vx, bot); ctx.stroke();

            const hy    = this._w2c(0, i)[1];
            const left  = this._w2c(-5, 0)[0];
            const right = this._w2c( 5, 0)[0];
            ctx.beginPath(); ctx.moveTo(left, hy); ctx.lineTo(right, hy); ctx.stroke();
        }

        ctx.strokeStyle = COLORS.axis; ctx.lineWidth = 1.5;
        ctx.beginPath(); ctx.moveTo(0,  oy); ctx.lineTo(W, oy); ctx.stroke();
        ctx.beginPath(); ctx.moveTo(ox,  0); ctx.lineTo(ox, H); ctx.stroke();

        ctx.fillStyle = '#bbb'; ctx.font = '10px sans-serif'; ctx.textAlign = 'center';
        for (let j = -4; j <= 4; j++) {
            if (j === 0) continue;
            const xc = this._w2c(j, 0)[0];
            ctx.fillText(j, xc, oy + 14);
            const yc = this._w2c(0, j)[1];
            ctx.textAlign = 'right';
            ctx.fillText(j, ox - 4, yc + 4);
            ctx.textAlign = 'center';
        }
    }

    _arrow(from, to, color, label) {
        const { ctx } = this;
        const [fx, fy] = from;
        const [tx, ty] = to;
        const ang = Math.atan2(ty - fy, tx - fx);
        if (Math.hypot(tx - fx, ty - fy) < 4) return;

        ctx.strokeStyle = color; ctx.fillStyle = color; ctx.lineWidth = 2.5;
        ctx.beginPath(); ctx.moveTo(fx, fy); ctx.lineTo(tx, ty); ctx.stroke();

        const aL = 13, aA = 0.38;
        ctx.beginPath();
        ctx.moveTo(tx, ty);
        ctx.lineTo(tx - aL * Math.cos(ang - aA), ty - aL * Math.sin(ang - aA));
        ctx.lineTo(tx - aL * Math.cos(ang + aA), ty - aL * Math.sin(ang + aA));
        ctx.closePath(); ctx.fill();

        if (label) {
            ctx.font = 'bold 14px sans-serif'; ctx.fillStyle = color;
            ctx.fillText(label, tx + 14 * Math.cos(ang - 1.0), ty + 14 * Math.sin(ang - 1.0) - 4);
        }
    }

    _dot(x, y, color, r = 7) {
        const { ctx } = this;
        ctx.beginPath(); ctx.arc(x, y, r, 0, 2 * Math.PI);
        ctx.fillStyle = color; ctx.fill();
        ctx.strokeStyle = '#fff'; ctx.lineWidth = 2; ctx.stroke();
    }

    _rightAngle(cx, cy, ang1, ang2, size = 9) {
        const { ctx } = this;
        ctx.strokeStyle = '#aaa'; ctx.lineWidth = 1.2;
        const p1x = cx + size * Math.cos(ang1), p1y = cy + size * Math.sin(ang1);
        const p2x = cx + size * Math.cos(ang2), p2y = cy + size * Math.sin(ang2);
        ctx.beginPath();
        ctx.moveTo(p1x, p1y);
        ctx.lineTo(p1x + size * Math.cos(ang2), p1y + size * Math.sin(ang2));
        ctx.lineTo(p2x, p2y);
        ctx.stroke();
    }

    /* ── Modes de visualisation ──────────────────────── */
    _drawVectors(ax, ay, bx, by) {
        const { ox, oy } = this;
        this._arrow([ox, oy], [ax, ay], COLORS.a, 'A');
        this._arrow([ox, oy], [bx, by], COLORS.b, 'B');
        this._dot(ax, ay, COLORS.a);
        this._dot(bx, by, COLORS.b);
    }

    _drawEuclidean(ax, ay, bx, by) {
        const { ctx } = this;
        ctx.setLineDash([7, 5]); ctx.strokeStyle = COLORS.green; ctx.lineWidth = 2.5;
        ctx.beginPath(); ctx.moveTo(ax, ay); ctx.lineTo(bx, by); ctx.stroke();
        ctx.setLineDash([]);
        this._dot(ax, ay, COLORS.a);
        this._dot(bx, by, COLORS.b);
        ctx.font = 'bold 13px sans-serif';
        ctx.fillStyle = COLORS.a; ctx.textAlign = 'left'; ctx.fillText('A', ax + 12, ay - 8);
        ctx.fillStyle = COLORS.b; ctx.fillText('B', bx + 12, by - 8);
        ctx.textAlign = 'center';
    }

    _drawManhattan(ax, ay, bx, by) {
        const { ctx } = this;
        ctx.setLineDash([3, 6]); ctx.strokeStyle = '#ccc'; ctx.lineWidth = 1;
        ctx.beginPath(); ctx.moveTo(ax, ay); ctx.lineTo(bx, by); ctx.stroke();
        ctx.setLineDash([]);

        ctx.strokeStyle = COLORS.green; ctx.lineWidth = 2.5; ctx.setLineDash([7, 5]);
        ctx.beginPath(); ctx.moveTo(ax, ay); ctx.lineTo(bx, ay); ctx.lineTo(bx, by); ctx.stroke();
        ctx.setLineDash([]);

        const hAng = bx > ax ?  0 : Math.PI;
        const vAng = by > ay ? Math.PI / 2 : -Math.PI / 2;
        this._rightAngle(bx, ay, hAng + Math.PI, vAng);

        const dx = this.vB.x - this.vA.x;
        const dy = this.vB.y - this.vA.y;
        ctx.fillStyle = COLORS.green; ctx.font = '11px monospace'; ctx.textAlign = 'center';
        ctx.fillText(`|Δx|=${Math.abs(dx).toFixed(1)}`, (ax + bx) / 2, ay - 7);
        ctx.textAlign = 'left';
        ctx.fillText(`|Δy|=${Math.abs(dy).toFixed(1)}`, bx + 6, (ay + by) / 2 + 4);
        ctx.textAlign = 'center';

        this._dot(ax, ay, COLORS.a);
        this._dot(bx, by, COLORS.b);
        ctx.font = 'bold 13px sans-serif';
        ctx.fillStyle = COLORS.a; ctx.textAlign = 'right'; ctx.fillText('A', ax - 10, ay - 8);
        ctx.fillStyle = COLORS.b; ctx.textAlign = 'left';  ctx.fillText('B', bx + 12, by + 16);
        ctx.textAlign = 'center';
    }

    _drawDotProduct(ax, ay, bx, by) {
        const { ctx, ox, oy } = this;
        const bLen = Math.hypot(this.vB.x, this.vB.y);
        if (bLen > 0.05) {
            const bNx  = this.vB.x / bLen;
            const bNy  = this.vB.y / bLen;
            const proj = this.vA.x * bNx + this.vA.y * bNy;
            const [px, py] = this._w2c(proj * bNx, proj * bNy);
            ctx.setLineDash([4, 4]); ctx.strokeStyle = '#bbb'; ctx.lineWidth = 1.5;
            ctx.beginPath(); ctx.moveTo(ax, ay); ctx.lineTo(px, py); ctx.stroke();
            ctx.setLineDash([]);
            ctx.beginPath(); ctx.arc(px, py, 5, 0, 2 * Math.PI);
            ctx.fillStyle = COLORS.proj; ctx.fill();
        }
        this._arrow([ox, oy], [ax, ay], COLORS.a, 'A');
        this._arrow([ox, oy], [bx, by], COLORS.b, 'B');
        this._dot(ax, ay, COLORS.a);
        this._dot(bx, by, COLORS.b);
    }

    _drawCosine(ax, ay, bx, by) {
        const { ctx, ox, oy } = this;
        this._arrow([ox, oy], [ax, ay], COLORS.a, 'A');
        this._arrow([ox, oy], [bx, by], COLORS.b, 'B');

        const angA = Math.atan2(-this.vA.y, this.vA.x);
        const angB = Math.atan2(-this.vB.y, this.vB.x);
        let s = Math.min(angA, angB);
        let e = Math.max(angA, angB);
        if (e - s > Math.PI) { [s, e] = [e, s + 2 * Math.PI]; }
        ctx.strokeStyle = COLORS.arc; ctx.lineWidth = 2.5;
        ctx.beginPath(); ctx.arc(ox, oy, 40, s, e); ctx.stroke();
        const mid = (s + e) / 2;
        ctx.fillStyle = COLORS.arc; ctx.font = 'bold 14px sans-serif';
        ctx.fillText('θ', ox + 58 * Math.cos(mid), oy + 58 * Math.sin(mid));

        this._dot(ax, ay, COLORS.a);
        this._dot(bx, by, COLORS.b);
    }

    /* ── Mise à jour des éléments HTML ───────────────── */
    _updateOutputs() {
        const set = (id, v) => { const el = document.getElementById(id); if (el) el.textContent = v; };
        const fmt = v => v.toFixed(2);
        const { x: ax, y: ay } = this.vA;
        const { x: bx, y: by } = this.vB;
        const dx   = bx - ax, dy = by - ay;
        const dot  = ax * bx + ay * by;
        const lenA = Math.hypot(ax, ay), lenB = Math.hypot(bx, by);
        const eucl = Math.hypot(dx, dy);
        const manh = Math.abs(dx) + Math.abs(dy);
        const cosV = (lenA > 0 && lenB > 0) ? dot / (lenA * lenB) : 0;
        const deg  = (lenA > 0 && lenB > 0) ? Math.acos(Math.max(-1, Math.min(1, cosV))) * 180 / Math.PI : 0;
        const { ids } = this;

        set(ids.ax, fmt(ax)); set(ids.ay, fmt(ay));
        set(ids.bx, fmt(bx)); set(ids.by, fmt(by));

        if (this.mode === 'euclidean') {
            set(ids.formula, `√(${fmt(Math.abs(dx))}² + ${fmt(Math.abs(dy))}²)`);
            set(ids.result, fmt(eucl));
        } else if (this.mode === 'manhattan') {
            set(ids.formula, `|${fmt(dx)}| + |${fmt(dy)}|`);
            set(ids.result, fmt(manh));
        } else if (this.mode === 'dotproduct') {
            set(ids.formula, `${fmt(ax)} × ${fmt(bx)} + ${fmt(ay)} × ${fmt(by)}`);
            set(ids.result, fmt(dot));
            const rEl = document.getElementById(ids.result);
            if (rEl) rEl.style.color = dot >= 0 ? '#27ae60' : '#e74c3c';
        } else if (this.mode === 'cosine') {
            set(ids.formula, `θ = ${fmt(deg)}°`);
            set(ids.result, `${fmt(cosV)}   (θ = ${fmt(deg)}°)`);
            const cEl = document.getElementById(ids.result);
            if (cEl) cEl.style.color = `hsl(${Math.round((cosV + 1) / 2 * 120)},70%,40%)`;
        }
    }

    /* ── Rendu principal ──────────────────────────────── */
    _refresh() {
        const { ctx } = this;
        ctx.clearRect(0, 0, this.W, this.H);
        ctx.fillStyle = '#f8f9fa'; ctx.fillRect(0, 0, this.W, this.H);
        this._drawGrid();

        const [ax, ay] = this._w2c(this.vA.x, this.vA.y);
        const [bx, by] = this._w2c(this.vB.x, this.vB.y);

        switch (this.mode) {
            case 'vectors':    this._drawVectors   (ax, ay, bx, by); break;
            case 'euclidean':  this._drawEuclidean (ax, ay, bx, by); break;
            case 'manhattan':  this._drawManhattan (ax, ay, bx, by); break;
            case 'dotproduct': this._drawDotProduct(ax, ay, bx, by); break;
            case 'cosine':     this._drawCosine    (ax, ay, bx, by); break;
        }
        this._updateOutputs();
    }
}

