// ─────────────────────────────────────────────────────────────────────────────

function _hmColor(v, vmin, vmax) {
    const t   = (v - vmin) / (vmax - vmin);   // 0..1
    const mid = -vmin / (vmax - vmin);         // position du zéro
    let r, g, b;
    if (t <= mid) {
        const s = mid > 0 ? t / mid : 0;
        r = Math.round(59  + s * (255 - 59));
        g = Math.round(130 + s * (255 - 130));
        b = Math.round(246 + s * (255 - 246));
    } else {
        const s = mid < 1 ? (t - mid) / (1 - mid) : 1;
        r = 255;
        g = Math.round(255 - s * (255 - 68));
        b = Math.round(255 - s * (255 - 68));
    }
    return `rgb(${r},${g},${b})`;
}

function _drawHeatmap(canvas, embedding, cell = HM_CELL) {
    const ctx  = canvas.getContext('2d');
    const vmin = embedding.reduce((m, v) => v < m ? v : m,  Infinity);
    const vmax = embedding.reduce((m, v) => v > m ? v : m, -Infinity);
    for (let row = 0; row < HM_ROWS; row++) {
        for (let col = 0; col < HM_COLS; col++) {
            ctx.fillStyle = _hmColor(embedding[row * HM_COLS + col], vmin, vmax);
            ctx.fillRect(col * cell, row * cell, cell, cell);
        }
    }
}

function _drawLegend(canvas) {
    const ctx = canvas.getContext('2d');
    const grd = ctx.createLinearGradient(0, 0, canvas.width, 0);
    grd.addColorStop(0,   'rgb(59,130,246)');
    grd.addColorStop(0.5, 'rgb(255,255,255)');
    grd.addColorStop(1,   'rgb(239,68,68)');
    ctx.fillStyle = grd;
    ctx.fillRect(0, 0, canvas.width, canvas.height);
}

function _cosineSim(a, b) {
    const dot = a.reduce((s, ai, i) => s + ai * b[i], 0);
    const na  = Math.sqrt(a.reduce((s, ai) => s + ai * ai, 0));
    const nb  = Math.sqrt(b.reduce((s, bi) => s + bi * bi, 0));
    return dot / (na * nb);
}

/* ── Dialog de comparaison ───────────────────────────────────── */
function _buildDialog() {
    const dlg = document.createElement('dialog');
    dlg.className = 'vs-dialog';
    dlg.innerHTML = `
        <div class="vs-dialog-header">
            <span>Comparaison vectorielle</span>
            <button class="vs-dialog-close" aria-label="Fermer">✕</button>
        </div>
        <div class="vs-dialog-row">
            <div class="vs-heatmap-item">
                <div class="vs-heatmap-label" id="vs-dlg-label-a"></div>
                <canvas id="vs-dlg-hm-a" class="vs-heatmap-canvas" width="192" height="128"></canvas>
            </div>
            <div class="vs-dialog-op">+</div>
            <div class="vs-heatmap-item">
                <div class="vs-heatmap-label" id="vs-dlg-label-b"></div>
                <canvas id="vs-dlg-hm-b" class="vs-heatmap-canvas" width="192" height="128"></canvas>
            </div>
            <div class="vs-dialog-op">=</div>
            <div class="vs-heatmap-item">
                <div class="vs-heatmap-label">Somme</div>
                <canvas id="vs-dlg-hm-sum" class="vs-heatmap-canvas" width="192" height="128"></canvas>
            </div>
        </div>
        <div class="vs-dialog-footer">
            Similarité cosinus : <strong class="vs-result" id="vs-dlg-sim"></strong>
        </div>`;
    dlg.querySelector('.vs-dialog-close').addEventListener('click', () => dlg.close());
    dlg.addEventListener('click', e => { if (e.target === dlg) dlg.close(); });
    document.body.appendChild(dlg);
    return dlg;
}

function _openComparison(dlg, idxA, idxB) {
    const embA = HEATMAP_DATA[idxA].embedding;
    const embB = HEATMAP_DATA[idxB].embedding;
    const sum  = embA.map((v, k) => v + embB[k]);

    _drawHeatmap(document.getElementById('vs-dlg-hm-a'),   embA, 8);
    _drawHeatmap(document.getElementById('vs-dlg-hm-b'),   embB, 8);
    _drawHeatmap(document.getElementById('vs-dlg-hm-sum'), sum,  8);

    const strip = s => s.replace(/^[^·]+· /, '');
    document.getElementById('vs-dlg-label-a').textContent = strip(HEATMAP_DATA[idxA].label);
    document.getElementById('vs-dlg-label-b').textContent = strip(HEATMAP_DATA[idxB].label);

    const sim   = _cosineSim(embA, embB);
    const simEl = document.getElementById('vs-dlg-sim');
    simEl.textContent = sim.toFixed(4);
    simEl.style.color = `hsl(${Math.round((sim + 1) / 2 * 120)},70%,40%)`;

    dlg.showModal();
}

export function initHeatmapWidget() {
    HEATMAP_DATA.forEach(({ embedding }, i) => {
        const cv = document.getElementById(`vs-hm-${i}`);
        if (cv) _drawHeatmap(cv, embedding);
    });

    const legend = document.getElementById('vs-hm-legend');
    if (legend) _drawLegend(legend);

    [[0,1],[0,2],[1,2]].forEach(([i, j]) => {
        const el = document.getElementById(`vs-hm-sim-${i}${j}`);
        if (!el) return;
        const sim = _cosineSim(HEATMAP_DATA[i].embedding, HEATMAP_DATA[j].embedding);
        el.textContent = sim.toFixed(3);
        el.style.color = `hsl(${Math.round((sim + 1) / 2 * 120)},70%,40%)`;
    });

    // Sélection par clic (2 heatmaps → dialog)
    const dlg = _buildDialog();
    let firstIdx = null;

    HEATMAP_DATA.forEach((_, i) => {
        const cv = document.getElementById(`vs-hm-${i}`);
        if (!cv) return;
        cv.addEventListener('click', () => {
            if (firstIdx === null) {
                firstIdx = i;
                cv.classList.add('vs-heatmap-selected');
            } else if (firstIdx === i) {
                firstIdx = null;
                cv.classList.remove('vs-heatmap-selected');
            } else {
                document.getElementById(`vs-hm-${firstIdx}`).classList.remove('vs-heatmap-selected');
                _openComparison(dlg, firstIdx, i);
                firstIdx = null;
            }
        });
    });
}

/* ── Point d'entrée ────────────────────────────────────────────────────────── */
export function initVectorWidgets() {
    new VecWidget('vs-canvas-vec',  'vectors',
        { x:  3, y: 2 }, { x: -1, y: 3 },
        { ax:'vs-va-x', ay:'vs-va-y', bx:'vs-vb-x', by:'vs-vb-y' });

    new VecWidget('vs-canvas-eucl', 'euclidean',
        { x: -2, y: -1 }, { x: 2, y: 3 },
        { ax:'vs-ea-x', ay:'vs-ea-y', bx:'vs-eb-x', by:'vs-eb-y',
          formula:'vs-eucl-formula', result:'vs-eucl-result' });

    new VecWidget('vs-canvas-manh', 'manhattan',
        { x: -2, y: -1 }, { x: 2, y: 3 },
        { ax:'vs-ma-x', ay:'vs-ma-y', bx:'vs-mb-x', by:'vs-mb-y',
          formula:'vs-manh-formula', result:'vs-manh-result' });

    new VecWidget('vs-canvas-dot',  'dotproduct',
        { x: 3, y: 1 }, { x: 1, y: 3 },
        { ax:'vs-da-x', ay:'vs-da-y', bx:'vs-db-x', by:'vs-db-y',
          formula:'vs-dot-formula',  result:'vs-dot-result' });

    new VecWidget('vs-canvas-cos',  'cosine',
        { x: 3, y: 1 }, { x: 1, y: 3 },
        { ax:'vs-ca-x', ay:'vs-ca-y', bx:'vs-cb-x', by:'vs-cb-y',
          formula:'vs-cos-formula',  result:'vs-cos-result' });
}
